+import { clamp } from "@excalidraw/math";
+
+export const EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX = 20;
+
+type EyeDropperPreviewPosition = {
+  top: number;
+  left: number;
+};
+
+type GetEyeDropperPreviewPositionParams = {
+  clientX: number;
+  clientY: number;
+  previewWidth: number;
+  previewHeight: number;
+  viewportWidth: number;
+  viewportHeight: number;
+  offset?: number;
+};
+
+export const getEyeDropperPreviewPosition = ({
+  clientX,
+  clientY,
+  previewWidth,
+  previewHeight,
+  viewportWidth,
+  viewportHeight,
+  offset = EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+}: GetEyeDropperPreviewPositionParams): EyeDropperPreviewPosition => {
+  const maxLeft = Math.max(viewportWidth - previewWidth, 0);
+  const maxTop = Math.max(viewportHeight - previewHeight, 0);
+
+  const left = clamp(
+    clientX + offset + previewWidth <= viewportWidth
+      ? clientX + offset
+      : clientX - previewWidth - offset,
+    0,
+    maxLeft,
+  );
+
+  const top = clamp(
+    clientY + offset + previewHeight <= viewportHeight
+      ? clientY + offset
+      : clientY - previewHeight - offset,
+    0,
+    maxTop,
+  );
+
+  return { top, left };
+};
