+import {
+  EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+  getEyeDropperPreviewPosition,
+} from "./EyeDropper.common";
+
+describe("getEyeDropperPreviewPosition", () => {
+  it("keeps the preview on the default side when it fits in the viewport", () => {
+    expect(
+      getEyeDropperPreviewPosition({
+        clientX: 100,
+        clientY: 80,
+        previewWidth: 48,
+        previewHeight: 48,
+        viewportWidth: 300,
+        viewportHeight: 240,
+      }),
+    ).toEqual({
+      left: 100 + EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+      top: 80 + EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+    });
+  });
+
+  it("flips the preview to the left when it would overflow the right edge", () => {
+    expect(
+      getEyeDropperPreviewPosition({
+        clientX: 280,
+        clientY: 80,
+        previewWidth: 48,
+        previewHeight: 48,
+        viewportWidth: 300,
+        viewportHeight: 240,
+      }),
+    ).toEqual({
+      left: 280 - 48 - EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+      top: 80 + EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+    });
+  });
+
+  it("flips the preview above the pointer when it would overflow the bottom edge", () => {
+    expect(
+      getEyeDropperPreviewPosition({
+        clientX: 100,
+        clientY: 220,
+        previewWidth: 48,
+        previewHeight: 48,
+        viewportWidth: 300,
+        viewportHeight: 240,
+      }),
+    ).toEqual({
+      left: 100 + EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+      top: 220 - 48 - EYE_DROPPER_PREVIEW_POINTER_OFFSET_PX,
+    });
+  });
+
+  it("clamps the preview inside the viewport when it cannot fit on either side", () => {
+    expect(
+      getEyeDropperPreviewPosition({
+        clientX: 30,
+        clientY: 30,
+        previewWidth: 48,
+        previewHeight: 48,
+        viewportWidth: 40,
+        viewportHeight: 40,
+      }),
+    ).toEqual({
+      left: 0,
+      top: 0,
+    });
+  });
+});
